return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n > 1);','language'=>'pt_BR','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-14 05:31:22+0000','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Atualize o plugin TranslatePress - Multilingual para a versão %1$s ou superior para garantir que %2$s funcione corretamente.','Please install and activate the TranslatePress - Multilingual plugin'=>'Instale e ative o plugin TranslatePress - Multilingual','Install & Activate'=>'Instalar e ativar','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Atualize o TranslatePress - Multilingual para a versão %2$s ou mais recente. A versão atualmente instalada do TranslatePress - Multilingual não é mais compatível com a versão atual do %1$s.','All TranslatePress functionalities are disabled until then.'=>'Todas as funcionalidades do TranslatePress estão desativadas até então.','Update Now'=>'Atualizar agora','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Este complemento do TranslatePress foi migrado para o plugin principal e não é mais usado. Você pode excluir.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'O <strong>TranslatePress</strong> requer pelo menos a versão 5.6.20+ do PHP para ser executado. Este é o <a href="%s">requisito mínimo da versão mais recente do WordPress</a>. Fale com o administrador do servidor para atualizar sua versão do PHP.','Advanced'=>'Avançado','Settings saved.'=>'Configurações salvas.','Are you sure you want to remove this item?'=>'Tem certeza de que deseja remover este item?','Remove'=>'Remover','Add'=>'Adicionar','Select...'=>'Selecione...','[%s] Low TranslatePress AI Words'=>'[%s] Limite baixo de palavras de IA do TranslatePress','upgrade your plan or get extra AI Words'=>'atualize seu plano, ou adquira mais palavras de IA','upgrade your plan'=>'atualizar seu plano','TranslatePress AI words are running low on your site.'=>'As palavras da IA do TranslatePress estão acabando no seu site.','Current status: %s words remaining'=>'Status atual: restam %s palavras','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Quando as palavras restantes de IA se esgotarem, a tradução automática pela IA do TranslatePress será interrompida.','To continue translating your content, please %1$s over at %2$s'=>'Para continuar traduzindo seu conteúdo, acesse %1$s em %2$s','Manage Notification: %s'=>'Gerenciar notificação: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Há uma nova versão do %1$s disponível. %2$sVer detalhes da versão %3$s%4$s ou %5$satualizar agora%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Há uma nova versão do %1$s disponível. %2$sVer detalhes da versão %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Para ativar as atualizações, %1$sdigite sua chave de licença%2$s. Precisa de uma chave de licença? %3$sCompre uma agora%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Para ativar as atualizações, acesse a página de %1$slicença%2$s e verifique se você tem uma licença válida.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Para ativar as atualizações, sua licença precisa ser renovada. Acesse a página da %1$sConta do TranslatePress%2$s e acesse para renovar.','You do not have permission to install plugin updates'=>'Você não tem permissão para instalar atualizações de plugins','Error'=>'Erro','Your TranslatePress license key is invalid or missing.'=>'Sua chave de licença do TranslatePress é inválida ou está ausente.','Your license key expired on %s.'=>'Sua chave de licença expirou em %s.','Your license key has been disabled.'=>'Sua chave de licença foi desativada.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Sua chave de licença está desativada para este URL. Reative-a em <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Gerenciar sites.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Chave de licença incompatível.</strong> A licença que você digitou não corresponde à versão do TranslatePress que você instalou.</p><p>Verifique se você instalou a versão correta para a sua licença na sua conta do TranslatePress.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Se você tiver apenas o plugin gratuito instalado, mas adicionou uma licença paga, instale o plugin pago a partir da sua conta do TranslatePress.','Your license key has reached its activation limit.'=>'Sua chave de licença atingiu o limite de ativação.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Atualize seu plano para adicionar mais sites. %1$sAtualize agora%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Este site já está ativado com uma licença gratuita. Cada site pode usar apenas uma licença gratuita.','An error occurred, please try again.'=>'Ocorreu um erro. Tente novamente.','You have successfully activated your license'=>'Você ativou sua licença','Others'=>'Outros','Restrict by Language'=>'Restringir por idioma','Exclude from Language'=>'Excluir do idioma','Restrict element to language'=>'Restringir o elemento ao idioma','Show this element only in one language.'=>'Mostrar este elemento apenas em um idioma.','Enable translation'=>'Ativar tradução','Allow translation to the corresponding language only if the content is written in the default language.'=>'Permita a tradução para o idioma correspondente, apenas se o conteúdo estiver escrito no idioma padrão.','Select language'=>'Selecionar idioma','Choose in which language to show this element.'=>'Escolha em qual idioma mostrar este elemento.','Exclude element from language'=>'Excluir elemento do idioma','Exclude this element from specific languages.'=>'Exclua este elemento de determinados idiomas.','Select languages'=>'Selecionar idiomas','Choose from which languages to exclude this element.'=>'Escolha de quais idiomas excluir este elemento.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Este elemento ainda estará visível quando você estiver traduzindo seu site através do editor de tradução.','The content of this element should be written in the default language.'=>'O conteúdo deste elemento precisa ser escrito no idioma padrão.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'O <strong>TranslatePress</strong> encontrou erros de SQL. <a href="%s" title="Ver erros de SQL do TranslatePress">Confira os erros</a>.','Automatic translation has been disabled.'=>'A tradução automática foi desativada.','Dismiss this notice.'=>'Dispensar esta notificação.','Logged errors'=>'Erros registrados','These are the most recent 5 errors logged by TranslatePress:'=>'Estes são os 5 erros mais recentes registrados pelo TranslatePress:','Yes'=>'Sim','Why are these errors occuring'=>'Por que estão ocorrendo estes erros','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Se o TranslatePress detectar algo errado ao executar consultas no seu banco de dados, ele pode desativar o recurso de tradução automática, para evitar qualquer cobrança adicional do Google/DeepL. A tradução automática precisa ser ativada manualmente, após você resolver os problemas.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Os erros de SQL detectados, podem ocorrer por vários motivos, incluindo tabelas ausentes, permissões ausentes para o usuário do SQL criar tabelas ou executar outras operações, problemas após a migração do site ou alterações na configuração do servidor SQL.','What you can do in this situation'=>'O que você pode fazer nesta situação','Plan A.'=>'Plano A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Acesse Configurações -> TranslatePress -> aba Geral e Salvar configurações. Isso irá gerar novamente as tabelas, usando suas configurações de SQL atuais. Confira se não há mais erros ao navegar pelo site em um idioma traduzido. Olhe os registros de data e hora dos erros para ter certeza de que não está vendo os erros antigos. Apenas os 5 erros mais recentes são exibidos.','Plan B.'=>'Plano B.','If your problem isn\'t solved, try the following steps:'=>'Se o problema não for solucionado, tente as etapas a seguir:','Create a backup of your database'=>'Crie um backup do seu banco de dados','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Crie uma cópia de cada tabela de tradução onde você encontrar erros. Você pode copiar a tabela dentro do mesmo banco de dados (trp_dictionary_en_us_es_es_COPY, por exemplo) - execute esta etapa apenas se quiser manter as traduções atuais','Remove the trouble tables by executing the DROP function on them'=>'Remova as tabelas com problemas, executando a função “DROP” nelas','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Acesse Configurações -> TranslatePress -> aba Geral e Salvar configurações. Isso irá gerar novamente as tabelas, usando seu servidor de SQL atual.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Copie o conteúdo relevante das tabelas duplicadas (trp_dictionary_en_us_es_es_COPY, por exemplo) na tabela recém-gerada (trp_dictionary_en_us_es_es) - execute esta etapa apenas se quiser manter as traduções atuais','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Teste para ver se tudo está funcionando. Se algo der errado, você poderá restaurar o backup feito na primeira etapa. Confira se não há mais erros ao navegar pelo site em um idioma traduzido. Olhe os registros de data e hora dos erros para ter certeza de que não está vendo os erros antigos. Apenas os 5 erros mais recentes são exibidos.','Plan C.'=>'Plano C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Se o problema ainda não tiver sido solucionado, tente perguntar ao seu provedor de hospedagem sobre os erros. O problema mais comum é a ausência de permissões para o usuário de SQL, como a permissão “Criar tabelas”.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Não foi possível instalar. Tente novamente a partir do <a href="%s" >Painel de plugins.</a>','Active'=>'Ativo','Permission denied.'=>'Permissão negada.','Invalid nonce.'=>'Nonce inválido.','Settings scope unknown.'=>'Escopo das configurações desconhecido.','Legacy disabled.'=>'Legado desativado.','Language Switcher'=>'Seletor de idiomas','Change language to %s'=>'Alterar o idioma para %s','Automatic Translation'=>'Tradução automática','DeepL'=>'DeepL','Unsupported languages'=>'Idiomas não suportados','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'O mecanismo de tradução automática selecionado, não oferece suporte para esses idiomas.<br>Você ainda pode traduzir manualmente as páginas nesses idiomas, usando o editor de tradução.','API key validation failed.'=>'Falha ao validar a chave de API.','API key verification was successful.'=>'A verificação da chave da API foi bem-sucedida.','Please enter your Google Translate key.'=>'Digite sua chave do Google Translate.','Please enter your DeepL API key.'=>'Digite sua chave de API do DeepL.','Not TranslatePress onboarding page.'=>'Não é a página de integração do TranslatePress.','Step %s does not exist'=>'A etapa %s não existe','Welcome'=>'Boas-vindas','Add Languages'=>'Adicionar idiomas','Enable Addons'=>'Ativar complementos','Finalize'=>'Concluir','Exit Setup'=>'Sair da configuração','Upgrade'=>'Atualizar','Nothing here'=>'Nada aqui','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Sua licença do <strong>TranslatePress</strong> está ausente ou é inválida. <br/>%1$sCadastre sua cópia%2$s para ativar a tradução automática do site através da IA do TranslatePress, complementos premium, atualizações automáticas e suporte. Precisa de uma chave de licença? %3$sCompre uma agora%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Sua licença do <strong>TranslatePress</strong> irá expirar em %1$s. %2$sRenove sua licença%3$s para continuar recebendo acesso a traduções automáticas através da IA do TP, complementos premium, baixar produtos e atualizações automáticas. %4$sRenove agora%5$s','Error: '=>'Erro: ','Something went wrong, please try again.'=>'Algo deu errado. Tente novamente.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Sua licença do <strong>TranslatePress</strong> expirou. <br/>%1$sRenove sua licença%2$s para continuar tendo acesso a traduções automáticas através da IA do TranslatePress, complementos premium, baixar produtos e atualizações automáticas. %3$sRenove agora %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Chave de licença incompatível. A licença que você digitou não corresponde à versão <strong>%1$s</strong> que você instalou. <br/>Verifique se você instalou a versão correta para a sua licença na sua %2$s conta do TranslatePress%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Se você tiver apenas o plugin gratuito instalado, mas adicionou uma licença paga, instale o plugin pago a partir da sua conta do TranslatePress.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Você atingiu o limite de ativação da sua licença <strong>%1$s</strong>. <br/>Gerencie seus sites ativos na %2$s sua conta %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Sua licença está desativada para este URL. Reative-a em <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Gerenciar sites.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'A tradução automática do %1$s requer uma licença ativa. %2$sRenove%3$s sua licença ou adquira uma nova %4$saqui%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Digite sua %1$schave de licença%2$s para ativar a tradução automática do %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Você tem menos de 5.000 palavras de IA do TranslatePress restantes. Para continuar traduzindo automaticamente seu site, %scompre palavras adicionais de IA com desconto na sua conta%s.',' Error: '=>' Erro: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Este site já está ativado com uma licença gratuita. Cada site pode usar apenas uma licença gratuita. Atualize para um plano premium, para ter mais palavras da IA do TranslatePress a partir de %1$s da sua conta %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Sua licença não é válida para o <strong>TranslatePress</strong>. %1$sAdquira uma gratuitamente%2$s para ter acesso à IA do TranslatePress.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NOVO:</strong> O complemento <strong>Domínio diferente por idioma</strong> já está disponível! Melhore seu SEO global e crie uma experiência local, com domínios específicos para cada país, como .de ou .fr. Atualize para o <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business ou Developer</a> para ter acesso a ele e a outras vantagens premium!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NOVO:</strong> O complemento <strong>Domínio diferente por idioma</strong> já está disponível! Melhore seu SEO global e crie uma experiência local com domínios específicos para cada país, como .de ou .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Saiba mais</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'A cota diária de caracteres de tradução automática foi excedida. Verifique a página <strong>TranslatePress -> <a href="%s">Tradução automática</a></strong> para mais informações.','Marketing optin'=>'Aceitação de marketing','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Aceite nossas notificações de atualizações de segurança e recursos, e o rastreamento de diagnósticos não sensíveis.','TranslatePress Preferred User Language'=>'Idioma preferido do usuário do TranslatePress','Preferred language to navigate the site'=>'Idioma preferido para navegar no site','The language is automatically set based by the last visited language by the user.'=>'O idioma é definido automaticamente, com base no último idioma acessado pelo usuário.','Always use this language'=>'Sempre usar este idioma','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Ao marcar esta configuração, o idioma preferido permanece o selecionado acima, sem a possibilidade de ser alterado na interface.<br>Este idioma será usado em diferentes operações, como o envio de e-mails ao usuário.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Olá! Parece que você já está usando o <strong>TranslatePress</strong> há um bom tempo para traduzir seu site. Isso é incrível! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Se você puder dedicar alguns minutos para classificá-lo no WordPress.org, isso nos ajudaria muito (e aumentaria minha motivação).','~ Razvan, developer of TranslatePress'=>'~ Razvan, desenvolvedor do TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Classifique o TranslatePress na página do plugin no WordPress.org','Ok, I will gladly help!'=>'Ok, terei prazer em ajudar!','No, thanks.'=>'Não.','Full Language Names'=>'Nomes completos dos idiomas','Short Language Names'=>'Nomes abreviados dos idiomas','Flags with Full Language Names'=>'Bandeiras com nomes completos dos idiomas','Flags with Short Language Names'=>'Bandeiras com nomes abreviados dos idiomas','Only Flags'=>'Apenas bandeiras','Full Language Names No HTML'=>'Nomes completos dos idiomas sem HTML','Bottom Right'=>'Inferior à direita','Bottom Left'=>'Inferior à esquerda','Top Right'=>'Superior à direita','Top Left'=>'Superior à esquerda','Dark'=>'Escuro','Light'=>'Claro','Deactivate'=>'Desativar','Activate'=>'Ativar','Invalid language code. Please try again.'=>'Código de idioma inválido. Tente novamente.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Os códigos de idioma podem conter apenas caracteres A-Z a-z 0-9 - _. Verifique seus códigos de idioma nas Configurações gerais do TranslatePress.','Error! Duplicate URL slug values.'=>'Erro! Valores de slug de URL duplicados.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Você não pode selecionar dois idiomas que tenham o mesmo <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">código iso</a>, mas com diferentes formalidades, pois isso fará com que as <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">tags hreflang sejam duplicadas</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Idioma duplicado detectado.<br>Cada idioma pode ser adicionado apenas uma vez, para garantir o gerenciamento preciso da tradução.<br>Altere a entrada do idioma duplicado e tente novamente. ','Current Language'=>'Idioma atual','Opposite Language'=>'Idioma oposto','General'=>'Geral','Translate Site'=>'Traduzir site','Addons'=>'Complementos','License'=>'Licença','Settings'=>'Configurações','Activate License'=>'Ativar licença','Pro Features'=>'Recursos Pro','Need Help?'=>'Precisa de ajuda?','Recent community discussions'=>'Discussões recentes da comunidade','Loading...'=>'Carregando…','Unable to load forum posts'=>'Não foi possível carregar os posts do fórum','Ask a Question'=>'Fazer uma pergunta','View All Topics'=>'Ver todos os tópicos','by'=>'por','Have a question?'=>'Tem alguma pergunta?','Get help directly 